import { gsap } from "../js/gsap-public/esm/index.js";
const NOOP = function(){}
//这个有个问题，就是无法监控到step内部的动作，这个实际上就完成了进度条的计算
//具体如何将DOM转化为AniBox的行为，应该是在step内部进行处理
//我们将timelinemax当成数据进度的中转站工具，我只要知道最后的数据就行了。
export class TimelineStep{
  constructor(options){
    this.options = options;
    this.steps = []
  }
  addStep(steps){
    steps.forEach(res => {
      const { st,et,step,onUpdate,params } = res;
      let tl = gsap.timeline({
        paused : true,
      });
      let step1 = step.call(res,tl);
      let obj = Object.assign({},res,{
        tl,
        onUpdate : res.onUpdate || NOOP,
      })
      this.steps.push(obj)
    })
    return this;
  }
  progress(progress){
    let steps = this.steps;
    let x = 0,y = 0;
    for(var i=0;i<steps.length;i++){
      let { st,et } = steps[i];
      x = i;
      let item = this.steps[x];
      if(progress > st && progress <= et){
        y = (progress - st) / (et - st)

        item.tl.progress(y);
        item.onUpdate.call(item,y);
      }else if(progress <= st){
        //在开始前
        item.tl.progress(0);
      }else if(progress >= et){
        //在结束后
        item.tl.progress(1);
      }
    }
  }
}

export { gsap }
